-- ── Cacio e Pepe
with new_recipe as (
  insert into public.recipes (
    title, description, cuisine, meal_type, allergens, dietary,
    prep_time_min, cook_time_min, servings,
    calories, protein, carbs, fat, fiber_g, sugar_g, sodium_mg,
    instructions, image_url, source_name, source_url,
    author_id, creator_id, published, is_verified
  ) values (
    'Cacio e Pepe',
    'Three-ingredient Roman pasta: tonnarelli, pecorino, and a punchy hit of black pepper.',
    'italian',
    ARRAY['lunch','dinner']::text[],
    ARRAY['dairy','gluten']::text[],
    '{"vegetarian":true}'::jsonb,
    5,
    12,
    2,
    580,
    22,
    80,
    18,
    3,
    2,
    780,
    '1. Bring a pot of water to a boil with about half the salt you''d normally use (the cheese is salty).

2. Toast peppercorns in a dry skillet over medium until fragrant. Coarsely crush in a mortar.

3. Cook pasta until very al dente, 1-2 minutes shy of package time.

4. Reserve 1 1/2 cups pasta water. Drain.

5. In a wide skillet, ladle 1/2 cup pasta water and the cracked pepper. Bring to a simmer 30 seconds.

6. Add the pasta with another splash of water. Off heat, sprinkle pecorino in handfuls, tossing vigorously, adding more water as needed until you have a glossy, creamy sauce that coats every strand.

7. Plate and finish with extra pepper and pecorino.',
    NULL,
    'Suppr Kitchen',
    NULL,
    NULL, NULL, true, true
  )
